sql:
SELECT SUM(salary) 
FROM players 
WHERE contract_expiration < 2025 AND salary > (SELECT AVG(salary) FROM players);

SELECT users.user_id, users.first_name, users.last_name, user_betting_history.bet_description
FROM users
INNER JOIN user_betting_history ON users.user_id = user_betting_history.user_id;

SELECT p.name, b.hits_odds
FROM players p
LEFT JOIN betting_lines b ON p.player_id = b.player_id;

external_knowledge:
- "still in the bloom of their career" refers to players with less than 1,000,000 salary and contract expiration beyond 2025;
- "not fully blossomed into full-blown superstars" means they have achieved at least one total base, hit, home run, or RBI, indicating some level of performance yet not overwhelming;
- "quietly enriching the team's value" signifies their contributions to the team's performance metrics;
- "extend their journey beyond the horizon of 2025" implies the contract expiration date is after 2025.

